content.text:
Here is a beautiful, highly interactive, and real-time synchronized **Kanban Tracker** designed specifically for your **XI Labs UX** workspace. 

It implements the native flat-file synchronization API `/api/sync` so that anyone opened in this sandbox environment can collaborate live on the board with seamless, real-time updates.

```html
<!-- index.html -->
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>XI Labs UX Kanban Tracker</title>
  <!-- Tailwind CSS CDN -->
  <script src="https://cdn.tailwindcss.com"></script>
  <!-- Google Fonts: Inter & Plus Jakarta Sans -->
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap" rel="stylesheet">
  <style>
    body {
      font-family: 'Inter', sans-serif;
    }
    h1, h2, h3, .font-display {
      font-family: 'Plus Jakarta Sans', sans-serif;
    }
    /* Custom scrollbar styling */
    ::-webkit-scrollbar {
      width: 6px;
      height: 6px;
    }
    ::-webkit-scrollbar-track {
      background: transparent;
    }
    ::-webkit-scrollbar-thumb {
      background: #cbd5e1;
      border-radius: 4px;
    }
    ::-webkit-scrollbar-thumb:hover {
      background: #94a3b8;
    }
  </style>
</head>
<body class="bg-gradient-to-br from-slate-50 to-slate-100 min-h-screen flex flex-col text-slate-800">

  <!-- Header Section -->
  <header class="bg-white/80 backdrop-blur-md sticky top-0 z-10 border-b border-slate-200/80 px-6 py-4 transition-all">
    <div class="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center md:justify-between gap-4">

      <!-- Brand & Sync Status -->
      <div class="flex items-center space-x-3">
        <div class="bg-indigo-600 text-white p-2.5 rounded-xl shadow-md shadow-indigo-100 flex items-center justify-center">
          <svg class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5" d="M9 17V7m0 10a2 2 0 21-2 2H5a2 2 0 21-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2" />
          </svg>
        </div>
        <div>
          <h1 class="text-xl font-extrabold tracking-tight text-slate-900">XI Labs UX</h1>
          <div class="flex items-center space-x-2 mt-0.5">
            <span class="relative flex h-2 w-2">
              <span id="sync-pulse" class="animate-ping absolute inline-flex h-full w-full rounded-full opacity-75"></span>
              <span id="sync-dot" class="relative inline-flex rounded-full h-2 w-2"></span>
            </span>
            <span id="sync-text" class="text-xs font-semibold text-slate-500 uppercase tracking-wider">Connecting...</span>
          </div>
        </div>
      </div>

      <!-- Controls & Search -->
      <div class="flex flex-wrap items-center gap-3">
        <!-- Search bar -->
        <div class="relative flex-grow md:flex-grow-0 md:w-64">
          <span class="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-slate-400">
            <svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
          </span>
          <input 
            type="text" 
            id="search-input" 
            placeholder="Search tasks..." 
            class="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm transition-all"
            oninput="handleSearch(this.value)"
          >
        </div>

        <!-- Priority filter -->
        <select 
          id="priority-filter" 
          class="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all"
          onchange="handlePriorityFilter(this.value)"
        >
          <option value="all">All Priorities</option>
          <option value="high">🔴 High</option>
          <option value="medium">🟡 Medium</option>
          <option value="low">🔵 Low</option>
        </select>

        <!-- New Task Button -->
        <button 
          onclick="openModal()" 
          class="bg-indigo-600 hover:bg-indigo-700 active:bg-indigo-800 text-white font-medium text-sm px-4 py-2.5 rounded-xl shadow-md shadow-indigo-100 hover:shadow-lg hover:shadow-indigo-200 transition-all flex items-center gap-1.5"
        >
          <svg class="w-4 h-4 stroke-[3px]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 4v16m8-8H4"/></svg>
          Add Task
        </button>
      </div>

    </div>
  </header>

  <!-- Workspace Board -->
  <main class="flex-grow p-6 max-w-7xl mx-auto w-full">
    <div class="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">

      <!-- TO DO Column -->
      <div 
        id="col-todo"
        class="bg-slate-100/50 rounded-2xl p-4 border border-slate-200/60 min-h-[600px] flex flex-col transition-all duration-200"
        ondragover="handleDragOver(event)"
        ondragleave="handleDragLeave(event)"
        ondrop="handleDrop(event, 'todo')"
      >
        <div class="flex items-center justify-between mb-4 px-1">
          <div class="flex items-center space-x-2">
            <span class="w-2.5 h-2.5 rounded-full bg-indigo-500"></span>
            <h2 class="font-bold text-slate-800 text-base">To Do</h2>
            <span id="count-todo" class="text-xs bg-slate-200 text-slate-600 font-bold px-2 py-0.5 rounded-full">0</span>
          </div>
          <button onclick="openModal('todo')" class="text-slate-400 hover:text-indigo-600 p-1 rounded-lg hover:bg-white transition-colors" title="Add task to To Do">
            <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5" d="M12 4v16m8-8H4"/></svg>
          </button>
        </div>
        <div id="tasks-todo" class="space-y-3 flex-grow overflow-y-auto"></div>
      </div>

      <!-- IN PROGRESS Column -->
      <div 
        id="col-progress"
        class="bg-slate-100/50 rounded-2xl p-4 border border-slate-200/60 min-h-[600px] flex flex-col transition-all duration-200"
        ondragover="handleDragOver(event)"
        ondragleave="handleDragLeave(event)"
        ondrop="handleDrop(event, 'progress')"
      >
        <div class="flex items-center justify-between mb-4 px-1">
          <div class="flex items-center space-x-2">
            <span class="w-2.5 h-2.5 rounded-full bg-amber-500 animate-pulse"></span>
            <h2 class="font-bold text-slate-800 text-base">In Progress</h2>
            <span id="count-progress" class="text-xs bg-slate-200 text-slate-600 font-bold px-2 py-0.5 rounded-full">0</span>
          </div>
          <button onclick="openModal('progress')" class="text-slate-400 hover:text-amber-600 p-1 rounded-lg hover:bg-white transition-colors" title="Add task to In Progress">
            <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5" d="M12 4v16m8-8H4"/></svg>
          </button>
        </div>
        <div id="tasks-progress" class="space-y-3 flex-grow overflow-y-auto"></div>
      </div>

      <!-- COMPLETED Column -->
      <div 
        id="col-done"
        class="bg-slate-100/50 rounded-2xl p-4 border border-slate-200/60 min-h-[600px] flex flex-col transition-all duration-200"
        ondragover="handleDragOver(event)"
        ondragleave="handleDragLeave(event)"
        ondrop="handleDrop(event, 'done')"
      >
        <div class="flex items-center justify-between mb-4 px-1">
          <div class="flex items-center space-x-2">
            <span class="w-2.5 h-2.5 rounded-full bg-emerald-500"></span>
            <h2 class="font-bold text-slate-800 text-base">Done</h2>
            <span id="count-done" class="text-xs bg-slate-200 text-slate-600 font-bold px-2 py-0.5 rounded-full">0</span>
          </div>
          <button onclick="openModal('done')" class="text-slate-400 hover:text-emerald-600 p-1 rounded-lg hover:bg-white transition-colors" title="Add task to Done">
            <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2.5" d="M12 4v16m8-8H4"/></svg>
          </button>
        </div>
        <div id="tasks-done" class="space-y-3 flex-grow overflow-y-auto"></div>
      </div>

    </div>
  </main>

  <!-- Task Detail Modal (Create / Edit) -->
  <div id="task-modal" class="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 hidden transition-all duration-300">
    <div class="bg-white rounded-2xl shadow-xl border border-slate-100 w-full max-w-lg overflow-hidden transform scale-95 transition-transform duration-300">

      <!-- Modal Header -->
      <div class="px-6 py-4 border-b border-slate-100 flex items-center justify-between">
        <h3 id="modal-title" class="font-bold text-lg text-slate-900">Add New Task</h3>
        <button onclick="closeModal()" class="text-slate-400 hover:text-slate-600 rounded-lg p-1.5 hover:bg-slate-100 transition-colors">
          <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"/></svg>
        </button>
      </div>

      <!-- Modal Body Form -->
      <form id="task-form" onsubmit="handleFormSubmit(event)" class="p-6 space-y-4">
        <input type="hidden" id="task-id">

        <div>
          <label class="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-1.5" for="form-title">Title</label>
          <input 
            type="text" 
            id="form-title" 
            required 
            placeholder="e.g. Implement Lab D65 color matrix conversion" 
            class="w-full px-3.5 py-2 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all text-sm"
          >
        </div>

        <div>
          <label class="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-1.5" for="form-desc">Description</label>
          <textarea 
            id="form-desc" 
            rows="3" 
            placeholder="Detail the acceptance criteria or implementation plan..." 
            class="w-full px-3.5 py-2 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all text-sm"
          ></textarea>
        </div>

        <div class="grid grid-cols-2 gap-4">
          <div>
            <label class="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-1.5" for="form-priority">Priority</label>
            <select id="form-priority" class="w-full px-3 py-2 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm transition-all">
              <option value="low">🔵 Low</option>
              <option value="medium">🟡 Medium</option>
              <option value="high">🔴 High</option>
            </select>
          </div>
          <div>
            <label class="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-1.5" for="form-column">Column</label>
            <select id="form-column" class="w-full px-3 py-2 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm transition-all">
              <option value="todo">To Do</option>
              <option value="progress">In Progress</option>
              <option value="done">Done</option>
            </select>
          </div>
        </div>

        <div class="grid grid-cols-2 gap-4">
          <div>
            <label class="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-1.5" for="form-assignee">Assignee</label>
            <select id="form-assignee" class="w-full px-3 py-2 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm transition-all">
              <option value="Unassigned">Unassigned</option>
              <option value="Alan McLean">Alan McLean</option>
              <option value="Daniel Giuditta">Daniel Giuditta</option>
              <option value="Dan Park">Dan Park</option>
              <option value="Kaushal Shah">Kaushal Shah</option>
              <option value="Simon Sok">Simon Sok</option>
            </select>
          </div>
          <div>
            <label class="block text-xs font-bold uppercase tracking-wider text-slate-500 mb-1.5" for="form-category">Category</label>
            <input 
              type="text" 
              id="form-category" 
              placeholder="e.g. Design, Dev, QA" 
              class="w-full px-3.5 py-2 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all text-sm"
            >
          </div>
        </div>

        <!-- Action buttons -->
        <div class="pt-4 flex items-center justify-end space-x-2 border-t border-slate-100 mt-4">
          <button 
            type="button" 
            onclick="closeModal()" 
            class="px-4 py-2 border border-slate-200 rounded-xl text-slate-600 hover:bg-slate-50 active:bg-slate-100 font-medium text-sm transition-all"
          >
            Cancel
          </button>
          <button 
            type="submit" 
            class="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 active:bg-indigo-800 text-white font-medium text-sm rounded-xl shadow-md shadow-indigo-100 transition-all"
          >
            Save Task
          </button>
        </div>

      </form>
    </div>
  </div>

  <script>
    // State Sync Metadata & Setup
    const envId = window.__sandboxEnvId;
    const syncKey = "xi_labs_kanban_board_state_v1";

    // Fallback Initial State with contextual items based on Standup Notes and Lab Color Conversion scripts
    const defaultState = {
      tasks: [
        {
          id: "task-color-d65",
          title: "Optimize Lab D65 matrix transformation",
          description: "Align base XYZ to D65 standard conversions defined in lab-d65.js according to CIE 15.3:2004 section 8.2.1.1.",
          column: "todo",
          priority: "high",
          category: "Development",
          assignee: "Daniel Giuditta",
          date: "2026-07-08"
        },
        {
          id: "task-k-means",
          title: "Refactor LabPointProvider distance formula",
          description: "Optimize standard CIE 1976 delta E formula in lab_point_provider.js to bypass square root for faster K-means quantization.",
          column: "progress",
          priority: "medium",
          category: "Refactoring",
          assignee: "Kaushal Shah",
          date: "2026-07-08"
        },
        {
          id: "task-ux-standup",
          title: "Prep XI Labs UX Prototyping Standup material",
          description: "Assemble high-fidelity prototype views and design token specs for the upcoming standup review session.",
          column: "done",
          priority: "low",
          category: "Design",
          assignee: "Alan McLean",
          date: "2026-06-16"
        }
      ]
    };

    let state = { tasks: [] };
    let searchQuery = "";
    let selectedPriority = "all";
    let isModalOpen = false;

    // Load initial state from local storage or sync server
    async function loadState() {
      if (envId) {
        try {
          const res = await fetch(`/api/sync/${envId}/${syncKey}`);
          const json = await res.json();
          if (json.data && json.data.tasks) {
            // Check if actual changes exist before updating to protect input states
            if (JSON.stringify(state.tasks) !== JSON.stringify(json.data.tasks)) {
              state = json.data;
              renderBoard();
            }
            updateSyncIndicator(true);
          } else {
            // Initialize with default state if sync is clean
            state = defaultState;
            await saveState();
            renderBoard();
          }
        } catch (err) {
          console.error("Failed to fetch synced state:", err);
          updateSyncIndicator(false, "Offline / Offline Mode");
        }
      } else {
        // Local-only environment fallback
        const local = localStorage.getItem(syncKey);
        if (local) {
          state = JSON.parse(local);
        } else {
          state = defaultState;
          localStorage.setItem(syncKey, JSON.stringify(state));
        }
        renderBoard();
        updateSyncIndicator(false, "Local Mode (No Sandbox ID)");
      }
    }

    // Save updated state to server and render
    async function saveState() {
      if (envId) {
        try {
          await fetch(`/api/sync/${envId}/${syncKey}`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ data: state })
          });
          updateSyncIndicator(true);
        } catch (err) {
          console.error("Failed to sync board state:", err);
          updateSyncIndicator(false, "Sync Error");
        }
      } else {
        localStorage.setItem(syncKey, JSON.stringify(state));
      }
    }

    // UI Indicator Setup
    function updateSyncIndicator(online, text) {
      const pulse = document.getElementById("sync-pulse");
      const dot = document.getElementById("sync-dot");
      const label = document.getElementById("sync-text");

      if (online) {
        pulse.className = "animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 bg-emerald-400";
        dot.className = "relative inline-flex rounded-full h-2 w-2 bg-emerald-500";
        label.innerText = "Live Multi-user Synced";
        label.className = "text-xs font-semibold text-emerald-600 uppercase tracking-wider";
      } else {
        pulse.className = "absolute inline-flex h-full w-full rounded-full opacity-0 bg-amber-400";
        dot.className = "relative inline-flex rounded-full h-2 w-2 bg-amber-500";
        label.innerText = text || "Offline Mode";
        label.className = "text-xs font-semibold text-amber-600 uppercase tracking-wider";
      }
    }

    // Handle Drag Over column
    function handleDragOver(e) {
      e.preventDefault();
      const col = e.currentTarget;
      col.classList.add("bg-indigo-50/50", "border-indigo-300");
    }

    // Handle Drag Leave column
    function handleDragLeave(e) {
      const col = e.currentTarget;
      col.classList.remove("bg-indigo-50/50", "border-indigo-300");
    }

    // Drop handler
    function handleDrop(e, columnId) {
      e.preventDefault();
      const col = e.currentTarget;
      col.classList.remove("bg-indigo-50/50", "border-indigo-300");

      const taskId = e.dataTransfer.getData("text/plain");
      const task = state.tasks.find(t => t.id === taskId);
      if (task && task.column !== columnId) {
        task.column = columnId;
        saveState();
        renderBoard();
      }
    }

    // Card drag start and end helpers
    function drag(e, id) {
      e.dataTransfer.setData("text/plain", id);
      setTimeout(() => {
        document.getElementById(`card-${id}`).classList.add("opacity-30");
      }, 0);
    }

    function dragEnd(id) {
      const card = document.getElementById(`card-${id}`);
      if (card) {
        card.classList.remove("opacity-30");
      }
    }

    // Move task with controls (useful on mobile & touch)
    function shiftTask(id, direction) {
      const task = state.tasks.find(t => t.id === id);
      if (!task) return;

      const columns = ["todo", "progress", "done"];
      const currentIndex = columns.indexOf(task.column);
      let nextIndex = currentIndex + direction;

      if (nextIndex >= 0 && nextIndex < columns.length) {
        task.column = columns[nextIndex];
        saveState();
        renderBoard();
      }
    }

    // Search and filters
    function handleSearch(val) {
      searchQuery = val.toLowerCase().trim();
      renderBoard();
    }

    function handlePriorityFilter(val) {
      selectedPriority = val;
      renderBoard();
    }

    // Modal Control
    function openModal(defaultCol = "todo", taskId = null) {
      isModalOpen = true;
      const modal = document.getElementById("task-modal");
      const form = document.getElementById("task-form");
      const titleEl = document.getElementById("modal-title");

      form.reset();

      if (taskId) {
        // Edit mode
        titleEl.innerText = "Edit Task";
        const task = state.tasks.find(t => t.id === taskId);
        if (task) {
          document.getElementById("task-id").value = task.id;
          document.getElementById("form-title").value = task.title;
          document.getElementById("form-desc").value = task.description;
          document.getElementById("form-priority").value = task.priority;
          document.getElementById("form-column").value = task.column;
          document.getElementById("form-assignee").value = task.assignee;
          document.getElementById("form-category").value = task.category || "";
        }
      } else {
        // Create mode
        titleEl.innerText = "Add New Task";
        document.getElementById("task-id").value = "";
        document.getElementById("form-column").value = defaultCol;
        document.getElementById("form-priority").value = "medium";
        document.getElementById("form-assignee").value = "Unassigned";
      }

      modal.classList.remove("hidden");
      setTimeout(() => {
        modal.firstElementChild.classList.remove("scale-95");
        modal.firstElementChild.classList.add("scale-100");
      }, 10);
    }

    function closeModal() {
      isModalOpen = false;
      const modal = document.getElementById("task-modal");
      modal.firstElementChild.classList.remove("scale-100");
      modal.firstElementChild.classList.add("scale-95");
      setTimeout(() => {
        modal.classList.add("hidden");
      }, 200);
    }

    // Task submit creation / edit updates
    function handleFormSubmit(e) {
      e.preventDefault();

      const id = document.getElementById("task-id").value;
      const title = document.getElementById("form-title").value.trim();
      const description = document.getElementById("form-desc").value.trim();
      const priority = document.getElementById("form-priority").value;
      const column = document.getElementById("form-column").value;
      const assignee = document.getElementById("form-assignee").value;
      const category = document.getElementById("form-category").value.trim();

      if (!title) return;

      if (id) {
        // Update existing
        const taskIndex = state.tasks.findIndex(t => t.id === id);
        if (taskIndex !== -1) {
          state.tasks[taskIndex] = {
            ...state.tasks[taskIndex],
            title,
            description,
            priority,
            column,
            assignee,
            category: category || "General"
          };
        }
      } else {
        // Create new
        const newTask = {
          id: 'task-' + Date.now(),
          title,
          description,
          priority,
          column,
          assignee,
          category: category || "General",
          date: new Date().toISOString().split('T')[0]
        };
        state.tasks.push(newTask);
      }

      closeModal();
      saveState();
      renderBoard();
    }

    // Delete task
    function deleteTask(id) {
      if (confirm("Are you sure you want to delete this task?")) {
        state.tasks = state.tasks.filter(t => t.id !== id);
        saveState();
        renderBoard();
      }
    }

    // Helper: Assignee initials and color code
    function getAssigneeMeta(name) {
      if (!name || name === "Unassigned") {
        return { initials: "?", bg: "bg-slate-200 text-slate-500" };
      }
      const parts = name.split(" ");
      const initials = parts.map(p => p[0]).join("").substring(0, 2).toUpperCase();

      // Seed color based on character codes
      const hash = name.split("").reduce((acc, char) => acc + char.charCodeAt(0), 0);
      const colors = [
        "bg-indigo-100 text-indigo-700",
        "bg-amber-100 text-amber-700",
        "bg-emerald-100 text-emerald-700",
        "bg-rose-100 text-rose-700",
        "bg-purple-100 text-purple-700",
        "bg-sky-100 text-sky-700"
      ];
      return { initials, bg: colors[hash % colors.length] };
    }

    // Render columns and cards
    function renderBoard() {
      const cols = {
